UPDATE order_info
SET order_status = #{newStatus},
    pay_status = 1,
    pay_time = #{payTime},
    update_time = NOW()
WHERE order_no = #{orderNo}
  AND user_id = #{userId}
  AND order_status = #{oldStatus}
  AND deleted = 0

UPDATE order_info
SET order_status = #{newStatus},
    ready_time = #{readyTime},
    update_time = NOW()
WHERE order_no = #{orderNo}
  AND merchant_id = #{merchantId}
  AND order_status = #{oldStatus}
  AND deleted = 0

