AND order_status = 3 AND finish_time IS NOT NULL AND DATE(finish_time) = CURDATE() AND deleted = 0 ORDER BY finish_time DESC LIMIT 100

SELECT COUNT(*) FROM order_info
WHERE user_id = #{userId}
  AND order_status = #{orderStatus}
  AND deleted = 0

SELECT COUNT(*) FROM order_info
WHERE merchant_id = #{merchantId}
  AND deleted = 0

SELECT COALESCE(SUM(pay_amount), 0) FROM order_info
WHERE merchant_id = #{merchantId}
  AND pay_status = 1
  AND DATE(pay_time) BETWEEN #{startDate} AND #{endDate}
  AND deleted = 0

SELECT COUNT(*) FROM order_info
WHERE merchant_id = #{merchantId}
  AND pay_status = 1
  AND DATE(pay_time) BETWEEN #{startDate} AND #{endDate}
  AND deleted = 0

SELECT COALESCE(SUM(pay_amount), 0) FROM order_info
WHERE merchant_id = #{merchantId}
  AND order_status = 5
  AND DATE(refund_time) BETWEEN #{startDate} AND #{endDate}
  AND deleted = 0

SELECT COUNT(DISTINCT user_id) FROM order_info
WHERE create_time >= #{since}
  AND deleted = 0

SELECT COUNT(DISTINCT merchant_id) FROM order_info
WHERE create_time >= #{since}
  AND deleted = 0

SELECT o.*, u.nickname AS user_nickname, u.phone AS user_phone, u.avatar AS user_avatar, m.merchant_name, m.contact_phone AS merchant_phone, s.store_name, s.detail_address AS store_address FROM order_info o LEFT JOIN user_info u ON o.user_id = u.id LEFT JOIN merchant_info m ON o.merchant_id = m.id LEFT JOIN store_info s ON o.store_id = s.id WHERE o.deleted = 0
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND (u.phone LIKE CONCAT('%', #{phone}, '%') OR m.contact_phone LIKE CONCAT('%', #{phone}, '%'))
AND o.merchant_id = #{merchantId}
AND o.order_status = #{status}
AND DATE(o.create_time) >= #{startDate}
AND DATE(o.create_time) <= #{endDate}
ORDER BY o.create_time DESC
